import torch
import triton
import triton.language as tl

def least_squares_qr(A, b, *, mode='reduced', out=None) -> torch.Tensor:
    if A.dim() < 2:
        raise ValueError("A must have at least 2 dimensions")
    if b.dim() < 1:
        raise ValueError("b must have at least 1 dimension")

    m, n = A.shape[-2], A.shape[-1]
    batch_shape = A.shape[:-2]

    if b.shape[-2] != m:
        raise ValueError("Incompatible dimensions between A and b")

    if mode == 'reduced':
        k = min(m, n)
    elif mode == 'complete':
        k = m
    else:
        raise ValueError("mode must be 'reduced' or 'complete'")

    # Handle batch dimensions
    if len(batch_shape) == 0:
        batch_size = 1
        batch_idx = None
    else:
        batch_size = 1
        for dim in batch_shape:
            batch_size *= dim
        batch_idx = tuple(range(len(batch_shape)))

    # Allocate output tensor
    if out is None:
        if b.dim() == 1:
            out = torch.empty(n, dtype=A.dtype, device=A.device)
        else:
            out = torch.empty(n, b.shape[-1], dtype=A.dtype, device=A.device)

    # Launch kernel
    if batch_size == 1:
        _least_squares_qr_kernel[1,](A, b, out, m, n, k, mode)
    else:
        grid = (batch_size, 1)
        _least_squares_qr_kernel[grid,](A, b, out, m, n, k, mode)

    return out

@triton.jit
def _least_squares_qr_kernel(A_ptr, b_ptr, x_ptr, m, n, k, mode):
    # Get thread index
    batch_idx = tl.program_id(0)

    # Compute offsets
    A_offset = batch_idx * m * n
    b_offset = batch_idx * m
    x_offset = batch_idx * n

    # Load A and b
    A = tl.load(A_ptr + A_offset + tl.arange(0, m)[:, None] * n + tl.arange(0, n)[None, :])
    b = tl.load(b_ptr + b_offset + tl.arange(0, m)[:, None])

    # Allocate memory for Q and R
    Q = tl.zeros((m, k), dtype=tl.float32)
    R = tl.zeros((k, n), dtype=tl.float32)

    # Initialize Q with A
    for i in range(m):
        for j in range(n):
            Q[i, j] = A[i, j]

    # QR decomposition using Givens rotations
    for j in range(min(m, n)):
        # Compute Householder reflector
        norm = 0.0
        for i in range(j, m):
            norm += Q[i, j] * Q[i, j]
        norm = tl.sqrt(norm)

        if norm > 1e-12:
            # Compute alpha
            alpha = -tl.sign(Q[j, j]) * norm

            # Compute beta
            beta = alpha * (alpha - Q[j, j])

            # Update Q
            for i in range(j, m):
                Q[i, j] = Q[i, j] / beta

            # Apply Householder transformation
            for i in range(j, m):
                dot = 0.0
                for l in range(j, n):
                    dot += Q[i, l] * Q[j, l]
                for l in range(j, n):
                    Q[i, l] = Q[i, l] - 2.0 * dot * Q[j, l]

            # Update R
            for i in range(j, n):
                R[j, i] = Q[j, i]

        # Copy remaining elements
        for i in range(j, n):
            if i >= j:
                R[j, i] = Q[j, i]
            else:
                R[j, i] = 0.0

    # Solve Rx = Q^T b
    # Compute Q^T b
    Qt_b = tl.zeros((k, 1), dtype=tl.float32)
    for i in range(k):
        for j in range(m):
            Qt_b[i, 0] += Q[j, i] * b[j, 0]

    # Back substitution
    for i in range(k - 1, -1, -1):
        temp = Qt_b[i, 0]
        for j in range(i + 1, k):
            temp -= R[i, j] * x_ptr[x_offset + j]
        x_ptr[x_offset + i] = temp / R[i, i]
